import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { FaGithub, FaLinkedin, FaEnvelope, FaPhone } from 'react-icons/fa';
import { HiArrowRight, HiDownload } from 'react-icons/hi';
import './Hero.css';

const Hero = () => {
  const [text, setText] = useState('');
  const [isDeleting, setIsDeleting] = useState(false);
  const [loopNum, setLoopNum] = useState(0);
  const [typingSpeed, setTypingSpeed] = useState(150);

  const roles = [
    'Full Stack Developer',
    'AI & Data Science Engineer',
    'Competitive Programmer',
    'Problem Solver'
  ];

  useEffect(() => {
    const handleType = () => {
      const i = loopNum % roles.length;
      const fullText = roles[i];

      setText(isDeleting 
        ? fullText.substring(0, text.length - 1)
        : fullText.substring(0, text.length + 1)
      );

      setTypingSpeed(isDeleting ? 50 : 150);

      if (!isDeleting && text === fullText) {
        setTimeout(() => setIsDeleting(true), 2000);
      } else if (isDeleting && text === '') {
        setIsDeleting(false);
        setLoopNum(loopNum + 1);
      }
    };

    const timer = setTimeout(handleType, typingSpeed);
    return () => clearTimeout(timer);
  }, [text, isDeleting, loopNum, typingSpeed, roles]);

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.15
      }
    }
  };

  const itemVariants = {
    hidden: { y: 30, opacity: 0 },
    visible: {
      y: 0,
      opacity: 1,
      transition: { duration: 0.6, ease: "easeOut" }
    }
  };

  return (
    <section className="hero" id="home">
      <div className="hero-background">
        <div className="grid-overlay"></div>
      </div>
      
      <div className="container">
        <motion.div 
          className="hero-wrapper"
          variants={containerVariants}
          initial="hidden"
          animate="visible"
        >
          <div className="hero-content-grid">
            {/* Left Content */}
            <div className="hero-left">
              <motion.div className="hero-badge" variants={itemVariants}>
                <span className="badge-dot"></span>
                <span>Available for opportunities</span>
              </motion.div>

              <motion.h1 className="hero-title" variants={itemVariants}>
                Hi, I'm <span className="gradient-text">Gowtham M</span>
              </motion.h1>

              <motion.div className="hero-subtitle" variants={itemVariants}>
                <span className="subtitle-text">{text}</span>
                <span className="cursor-blink">|</span>
              </motion.div>

              <motion.p className="hero-description" variants={itemVariants}>
                B.Tech graduate in AI & Data Science with 8.92 CGPA. 
                Specialized in full-stack development and competitive programming 
                with 1000+ problems solved across multiple platforms.
              </motion.p>

              <motion.div className="hero-cta" variants={itemVariants}>
                <a href="#projects" className="cta-primary">
                  <span>View Projects</span>
                  <HiArrowRight />
                </a>
                <a href="#contact" className="cta-secondary">
                  <span>Contact Me</span>
                </a>
              </motion.div>

              <motion.div className="hero-links" variants={itemVariants}>
                <a href="https://github.com/GowthamGowri-11" target="_blank" rel="noopener noreferrer" className="social-link">
                  <FaGithub />
                </a>
                <a href="https://linkedin.com/in/gowtham-m-0a83353771" target="_blank" rel="noopener noreferrer" className="social-link">
                  <FaLinkedin />
                </a>
                <a href="mailto:kit28.24bad049@gmail.com" className="social-link">
                  <FaEnvelope />
                </a>
                <a href="tel:+918154505751" className="social-link">
                  <FaPhone />
                </a>
              </motion.div>
            </div>

            {/* Right Content - Image */}
            <motion.div 
              className="hero-right"
              initial={{ opacity: 0, x: 50 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.8, delay: 0.3 }}
            >
              <div className="hero-image-frame">
                <img 
                  src="/profile.png" 
                  alt="Gowtham M" 
                  className="hero-image"
                />
                <div className="image-backdrop"></div>
              </div>

              {/* Stats Cards */}
              <div className="floating-stats">
                <motion.div 
                  className="stat-card"
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 1, duration: 0.5 }}
                >
                  <div className="stat-value">1000+</div>
                  <div className="stat-label">Problems Solved</div>
                </motion.div>

                <motion.div 
                  className="stat-card"
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 1.2, duration: 0.5 }}
                >
                  <div className="stat-value">8.92</div>
                  <div className="stat-label">CGPA</div>
                </motion.div>

                <motion.div 
                  className="stat-card"
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 1.4, duration: 0.5 }}
                >
                  <div className="stat-value">10+</div>
                  <div className="stat-label">Projects</div>
                </motion.div>
              </div>
            </motion.div>
          </div>
        </motion.div>
      </div>

      {/* Scroll Indicator */}
      <motion.a 
        href="#about"
        className="scroll-down"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 2 }}
      >
        <span>Scroll</span>
        <div className="scroll-line"></div>
      </motion.a>
    </section>
  );
};

export default Hero;
